def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(point1, point2):
        return np.linalg.norm(point1 - point2)

    prioritization_factor = len(unvisited_customers)  # Adjust factor based on the number of remaining unvisited customers
    penalty_for_delay = current_time * 0.05  # Increased penalty based on how much time has passed

    best_node = None
    optimal_strategy_value = float('inf')

    for i, customer in enumerate(unvisited_customers):
        travel_distance = calculate_distance(cur_truck_pos, customer)
        travel_time = travel_distance / truck_speed
        arrive_time = current_time + travel_time
        tw_start, tw_end = time_windows[i]

        if arrive_time > tw_end:
            urgency_penalty = (arrive_time - tw_end) * penalty_for_delay
        elif arrive_time < tw_start:
            urgency_penalty = (tw_start - arrive_time) * penalty_for_delay
        else:
            urgency_penalty = 0  # Arrives within the time window

        # Combining factors into a dynamic strategy value
        strategy_value = (travel_time / prioritization_factor) + urgency_penalty
        # Determine best node by minimum strategy value
        if strategy_value < optimal_strategy_value:
            optimal_strategy_value = strategy_value
            best_node = i

    return best_node

