import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def estimate_future_traffic(current_time, idx):
        # Very simple traffic fluctuation model based on time modulo
        return 0.9 + 0.2 * np.sin(current_time / 100 + idx)

    def calculate_future_penalty(starting_time, time_window):
        start, end = time_window
        if starting_time > end:
            return (starting_time - end) * 50  # significant penalty for missing window
        elif starting_time < start:
            return start - starting_time  # truck will wait till the window starts
        return 0  # in window - no penalty

    best_node = None
    min_cost = float('inf')

    for i, customer_pos in enumerate(unvisited_customers):
        distance = np.linalg.norm(cur_truck_pos - customer_pos)
        future_traffic = estimate_future_traffic(current_time, i)
        travel_time = distance / (truck_speed * future_traffic)
        total_time_at_customer = current_time + travel_time
        penalty = calculate_future_penalty(total_time_at_customer, time_windows[i])
        total_cost = travel_time + penalty

        if total_cost < min_cost:
            min_cost = total_cost
            best_node = i

    return best_node
